mapper.select:
SELECT id, tcm_herb_id, herb_name_zh, pinyin_name, latin_name, english_name, type, efficacy_zh, function_en, efficacy_category, toxicity_zh, toxic_en, toxic_description_zh, toxic_effect_en, pharmacopoeia_record, classification, classification_zh, use_part, nature_taste_zh, property_en, meridian_zh, meridian_tropism_en, indications_zh, indication_en FROM core_tcm_herbs
AND ( herb_name_zh LIKE CONCAT('%', #{keyword}, '%') OR pinyin_name LIKE CONCAT('%', #{keyword}, '%') OR latin_name LIKE CONCAT('%', #{keyword}, '%') OR classification LIKE CONCAT('%', #{keyword}, '%') OR classification_zh LIKE CONCAT('%', #{keyword}, '%') )
AND type = #{type}
AND efficacy_category = #{efficacyCategory}
ORDER BY id ASC
